export function t(key: I18nKey, lang: Language = defaultLanguage, params?: Record<string, string>): string {
	let text = translations[lang][key];
	if (params) {
		for (const [k, v] of Object.entries(params)) {
			text = text.replace(`{${k}}`, v);
		}
	}
	return text;
}
